def is_valid_move(board, from_pos, to_pos, player):
    x1, y1 = from_pos
    x2, y2 = to_pos

    # Check if the move is within the board boundaries
    if not (0 <= x1 < 8 and 0 <= y1 < 8 and 0 <= x2 < 8 and 0 <= y2 < 8):
        return False

    # Check if the start position contains a piece belonging to the player
    if board[x1][y1] == ' ' or (board[x1][y1].islower() != player.lower()):
        return False

    # Check if the move is diagonal
    if abs(x2 - x1) != 1 or abs(y2 - y1) != 1:
        return False

    # Check for captures
    if board[x1][y1] in 'br' and abs(y2 - y1) == 2:
        mid_x, mid_y = (x1 + x2) // 2, (y1 + y2) // 2
        if board[mid_x][mid_y] == ' ' or board[mid_x][mid_y].islower() == player.lower():
            return False

    # Check for valid moves without captures
    if board[x2][y2] != ' ':
        return False

    return True

