        board[x2][y2] = 'B'
    elif x2 == 7 and board[x2][y2].isupper():
        board[x2][y2] = 'R'

def capture_piece(board, from_pos, to_pos):
    mid_x, mid_y = (from_pos[0] + to_pos[0]) // 2, (from_pos[1] + to_pos[1]) // 2
    board[mid_x][mid_y] = ' '

def is_game_over(board):
    # Check for remaining pieces
    black_pieces = sum(row.count('b') for row in board)
    red_pieces = sum(row.count('r') for row in board)

    if black_pieces == 0:
        print("Red wins!")
        return True
    elif red_pieces == 0:
